UPDATE user_devices
SET fcm_token = #{fcmToken}, updated_at = NOW()
WHERE id = #{id}

UPDATE user_devices
fcm_token = #{fcmToken}, language = #{language}, is_active = #{isActive}, updated_at = NOW()
WHERE id = #{id} AND user_id = #{userId}

UPDATE user_devices
SET is_active = false, updated_at = NOW()
WHERE id = #{id}
